import processing dem = '/data/dem.tif'
outlets = '/data/outlets.shp' # Step 1: condition DEM
processing.run('whitebox_workflows:breach_depressions_least_cost', { 'dem': dem, 'max_dist': 10, 'max_depth': 2.0, 'flat_increment': 0.001, 'fill': True, 'output': '/data/dem_conditioned.tif',
}) # Step 2: flow direction
processing.run('whitebox_workflows:d8_pointer', { 'dem': '/data/dem_conditioned.tif', 'output': '/data/d8_pointer.tif',
}) # Step 3: flow accumulation
processing.run('whitebox_workflows:d8_flow_accumulation', { 'input': '/data/d8_pointer.tif', 'output_type': 'Cells', 'log': False, 'output': '/data/d8_accum.tif',
}) # Step 4: extract streams
processing.run('whitebox_workflows:extract_streams', { 'flow_accum': '/data/d8_accum.tif', 'threshold': 500.0, 'zero_background': True, 'output': '/data/streams.tif',
}) # Step 5: snap pour points
processing.run('whitebox_workflows:snap_pour_points', { 'pour_pts': outlets, 'flow_accum': '/data/d8_accum.tif', 'snap_dist': 200.0, 'output': '/data/outlets_snapped.shp',
}) # Step 6: watershed
processing.run('whitebox_workflows:watershed', { 'd8_pntr': '/data/d8_pointer.tif', 'pour_pts': '/data/outlets_snapped.shp', 'output': '/data/watersheds.tif',
}) print("Watershed delineation complete.")

